import axios from 'axios';
import { useEffect, useState } from 'react';

function App() {
  const [plots, setPlots] = useState([]);

  useEffect(() => {
    axios.get('http://localhost:5001/api/plots')
      .then(res => setPlots(res.data))
      .catch(err => console.error(err));
  }, []);

  const [name, setName] = useState('');
  const addPlot = async () => {
    const res = await axios.post('http://localhost:5001/api/plots', {
      name,
      size: "10x10"
    });
    setPlots([...plots, res.data]);
  };

  return (
    <div>
      <input 
  placeholder="Enter plot name"
  onChange={(e) => setName(e.target.value)} 
/>
<button onClick={addPlot}>Add Plot</button>
      <h1>Garden Plots</h1>
      {plots.map(plot => (
        <div key={plot._id}>
          {plot.name} - {plot.status}
        </div>
      ))}
    </div>
  );
}

export default App;
